// Auto-generated word filter bitmask (top 60k GloVe words passing English dictionary + length checks)
// bit i=1: GloVe index i is a valid common English word (no proper nouns/abbreviations)
const _bitmask = Uint8Array.from(atob(""), c => c.charCodeAt(0));

/** Returns true if the word at GloVe index i should be allowed in pair selection */
export function isValidPairWord(gloveIndex) {
    if (gloveIndex >= _bitmask.length * 8) return false;
    return !!(_bitmask[gloveIndex >> 3] >> (gloveIndex & 7) & 1);
}
